type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

export function runScenario(scenario: Scenario): { results: Array<{ premium: number }> } {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
    const firstInsurance = base * 0.1;
    const premium = Math.ceil(base + firstInsurance + 5);
    return { premium };
  });
  return { results };
}

