type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

function itemBasePremium(item: Item): number {
  return BASE_PREMIUM[item.type] ?? 0;
}

function componentGroupPremium(type: string, count: number): number {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const remainder = count % BLOCK_SIZE;
  return blocks * BLOCK_PREMIUM + remainder * BASE_PREMIUM[type];
}

function itemsBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    total += componentGroupPremium(type, count);
  }
  return total;
}

function quotePremium(items: Item[]): number {
  const base = itemsBasePremium(items);
  const beforeFee = base + base * FIRST_INSURANCE_RATE;
  return Math.ceil(beforeFee + PROCESSING_FEE);
}

export function runScenario(scenario: Scenario): { results: Array<{ premium: number }> } {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
}

