import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest cases ---
  it("empty item list quote → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums per main item type (each +5 G processing fee) ---
  it("quote with single sword → premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with single amulet → premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with single staff → premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote with single potion → premium 49 G (40 base + 4 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components: runes & moonstones ---
  it("quote 2 runes → base premium 50 G, total 60 G (50 + 5 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote 3 runes → base premium 60 G (block applies), total 71 G (60 + 6 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote 4 runes → base premium 100 G (no block — block requires exactly 3), total 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote 7 runes → base premium 175 G (all individual since count != 3), total 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // --- Alike components: only exact same type forms a block ---
  it("quote 2 runes + 1 moonstone → base premium 75 G (no block, different types)", () => {
    // 75 base × 1.1 = 82.5 + 5 = 87.5 → ceil 88
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote 3 runes + 3 moonstones → base premium 120 G (two separate blocks)", () => {
    // 120 × 1.1 + 5 = 137 → ceil 137
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Item-specific modifiers ---
  it("quote cursed sword (newcomer) → 165 G (100 base + 50 curse + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("quote sword enchantment 5 (high-enchantment threshold) adds 30 G surcharge");
  it.todo("quote sword enchantment 4 → no high-enchantment surcharge");
  it.todo("quote sword enchantment 5 AND cursed → both surcharges apply");

  // --- Modifier scope: cursed surcharge applies only to the cursed item's base premium ---
  it.todo("cursed sword + plain amulet (newcomer) → premium reflects cursed surcharge only on sword");

  // --- Policy-wide modifiers ---
  it.todo("customer with 2 years (threshold) → 20% loyalty discount applies on policy base premium");
  it.todo("customer with 1 year → no loyalty discount");
  it.todo("first-ever contract → 10% first-insurance surcharge on policy base premium");
  it.todo("second contract of customer → 15% follow-up discount on policy base premium");
  it.todo("processing fee of 5 G added at the very end");

  // --- Integration examples from spec ---
  it.todo("newcomer with a cursed sword (steel, ench 3), 0 yrs → premium 165 G");
  it.todo("long-standing customer's 2nd contract: cursed sword ench 7, 3 yrs → premium 160 G");

  // --- Rounding: premium rounds up (MHPCO's favor) ---
  it.todo("premium 197.5 G → rounded up to 198 G");

  // --- Claims: standard reimbursement ---
  it.todo("regular sword steel ench 3, damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance 250), damage 200 → payout 100 G");

  // --- Claims: enchantment threshold vs dragon material ---
  it.todo("dragon-material sword ench 8, damage 1000 → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword ench 9, damage 1000 → payout 400 G (both clauses, 50% wins)");
  it.todo("dragon-material sword ench 5, damage 800 → payout 700 G (dragon full, then deductible)");
  it.todo("steel sword ench 9, damage 1000 → payout 400 G (50% then deductible)");

  // --- Deductible per damage event (per item) ---
  it.todo("dragon attack damages sword 500 + amulet 300 → payout 600 G (100 deductible each)");

  // --- Multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000, cap 4000");
  it.todo("two swords, dragon attack damages both → each treated separately with its own deductible");
  it.todo("claim has more damages of a type than policy covers → non-zero exit, claim rejected");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value, premium modifiers don't raise cap)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 (block affects premium only, not insurance sum)");
  it.todo("sword (cap 2000), two successive claims of 1500: first payout 1400 cap remaining 600, second payout 600 cap remaining 0");

  // --- Rounding payouts ---
  it.todo("payout 350.5 G → rounded down to 350 G (MHPCO's favor)");
  it.todo("intermediate amounts kept as fractions; only final rounded");

  // --- Error / edge cases (CLI) ---
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, stderr, no results");
  it.todo("claim references item not in policy (amulet damaged when only sword insured) → CLI non-zero exit + stderr");
  it.todo("claim with damage amount -200 → CLI non-zero exit + stderr");

  // --- Sanity placeholder so the suite parses even with no executable tests ---
  it("placeholder so vitest has at least one runnable test", () => {
    expect(true).toBe(true);
  });
});

